def logic(x, y):
    N = len(x)
    Xf = np.fft.fft(x)
    h = np.zeros(N)
    # 建構解析訊號的頻域遮罩: 正頻率x2, 負頻率x0
    if N % 2 == 0:
        h[0] = h[N // 2] = 1
        h[1:N // 2] = 2
    else:
        h[0] = 1
        h[1:(N + 1) // 2] = 2
    analytic = np.fft.ifft(Xf * h)
    return np.abs(analytic)

