def logic(x, y):
    target_len = int(y.get('length', len(x))) if isinstance(y, dict) else int(y if y is not None else len(x))
    if target_len <= 0: return np.array([])
    if x.size < 2: return np.resize(x, target_len)
    # 建立舊座標與新座標進行插值
    old_indices = np.linspace(0, len(x)-1, len(x))
    new_indices = np.linspace(0, len(x)-1, target_len)
    return np.interp(new_indices, old_indices, x)

