def logic(x, y):
    w_type = y.get('type', 'hanning') if isinstance(y, dict) else (str(y) if y is not None else 'hanning')
    N = x.size
    if N == 0: return x
    if 'hamming' in w_type.lower():
        window = np.hamming(N)
    elif 'blackman' in w_type.lower():
        window = np.blackman(N)
    else:
        window = np.hanning(N)
    return x * window

