def logic(x, y):
    cfg = y if isinstance(y, dict) else {}
    high = cfg.get('high', 0.5)
    low = cfg.get('low', -0.5)
    out = np.zeros_like(x, dtype=float)
    state = 0.0
    # 使用迴圈處理狀態記憶 (Hysteresis)
    for i in range(len(x)):
        if x[i] >= high:
            state = 1.0
        elif x[i] <= low:
            state = 0.0
        out[i] = state
    return out

