import numpy as np

def logic(x, y):
    # 1. 確保 y 是陣列
    if not isinstance(y, (np.ndarray, list)):
        return np.array([0.0])
    y_arr = np.array(y)

    # 2. 邊界檢查
    if x.size < 2 or y_arr.size < 2:
        return np.array([0.0])

    # 3. 對齊長度 (Trim to min length)
    min_len = min(len(x), len(y_arr))
    x_core = x[:min_len]
    y_core = y_arr[:min_len]

    # 4. 計算相關係數矩陣 [ [1, r], [r, 1] ]
    # 取出 [0, 1] 位置的值
    r = np.corrcoef(x_core, y_core)[0, 1]

    # 處理 NaN 情況 (例如標準差為 0)
    if np.isnan(r): r = 0.0
    return np.array([r])

