import numpy as np

def logic(x, y):
    # 1. 確保 y 是陣列
    y_arr = np.array(y) if not isinstance(y, np.ndarray) else y
    n = min(len(x), len(y_arr))
    if n == 0: return np.array([])

    # 2. 組合複數頻譜 (Real + j*Imag)
    spectrum = x[:n] + 1j * y_arr[:n]

    # 3. 執行逆變換 (取實部回傳)
    return np.fft.irfft(spectrum)
